+            && buf[1] == ':' && buf[2] == '\\') {
+        *prefix = L"\\\\?\\";
+    } else if (buf[0] == '\\' && buf[1] == '\\') {
+        if (buf[2] == '?' && buf[3] == '\\') {
+            *prefix = L"";
+            *needs_fullpath = 0;
